// Topic: akilli-sinif/sinif-1/sensors/temperature
var parts = msg.topic.split('/');
var classroomId = parts[1];  // sinif-1
var sensorType = parts[3];   // temperature, humidity, camera, etc.

// Sensör tipine göre field adını belirle
var fieldName = "value";
var fieldValue = msg.payload.value;

// Boolean sensörler için özel işlem
if (sensorType === "pir") {
    fieldName = "detected";
    fieldValue = msg.payload.detected ? 1 : 0;
} else if (sensorType === "window") {
    fieldName = "open";
    fieldValue = msg.payload.open ? 1 : 0;
} else if (sensorType === "camera") {
    fieldName = "person_count";
    fieldValue = msg.payload.person_count || 0;
}

// InfluxDB v2 için mesajı hazırla
msg.measurement = sensorType;
var fields = {};
fields[fieldName] = fieldValue;
var tags = {
    classroom: classroomId,
    sensor: sensorType
};
msg.payload = [fields, tags];

return msg;

var parts = msg.topic.split('/');
var classroomId = parts[1];

msg.measurement = "device_status";
msg.payload = {
    classroom: classroomId,
    device: msg.payload.device || "unknown",
    online: msg.payload.status === "online" ? 1 : 0,
    rssi: msg.payload.rssi || 0,
    uptime: msg.payload.uptime || 0
};

return msg;

// Topic'e göre sensör verilerini global context'e kaydet
var parts = msg.topic.split('/');
var classroomId = parts[1];
var sensorType = parts[3];

// Global context key
var key = classroomId + '_' + sensorType;

// Sensör değerini kaydet
if (sensorType === 'camera') {
    global.set(classroomId + '_person_count', msg.payload.person_count || 0);
    return [msg, null, null];  // Output 1: Kişi sayısı değişti
} else if (sensorType === 'temperature') {
    global.set(classroomId + '_temperature', msg.payload.value);
    return [null, msg, null];  // Output 2: Sıcaklık değişti
} else if (sensorType === 'light') {
    global.set(classroomId + '_light', msg.payload.value);
    return [null, null, msg];  // Output 3: Işık değişti
}

return null;

// Kişi sayısı değiştiğinde kontrol et
var parts = msg.topic.split('/');
var classroomId = parts[1];
var personCount = msg.payload.person_count || 0;

// Otomasyon durumunu kontrol et
var autoMode = global.get(classroomId + '_auto_mode');
if (autoMode === false) {
    // Manuel mod, otomasyon kapalı
    return null;
}

if (personCount === 0) {
    // Sınıf boş - timer başlat
    var emptyTimer = global.get(classroomId + '_empty_timer');

    if (!emptyTimer) {
        // İlk kez boş, timestamp kaydet
        global.set(classroomId + '_empty_since', Date.now());
        global.set(classroomId + '_empty_timer', true);
        node.status({fill:'yellow', shape:'ring', text:'Sınıf boş, bekleniyor...'});
    }

    // 5 dakika (300000 ms) geçti mi?
    var emptySince = global.get(classroomId + '_empty_since');
    var elapsed = Date.now() - emptySince;

    if (elapsed >= 300000) {  // 5 dakika
        // LED ve Fan'ı kapat
        node.status({fill:'red', shape:'dot', text:'5 dk boş - Kapatılıyor'});

        msg.classroomId = classroomId;
        msg.action = 'turn_off_all';
        return msg;
    }
} else {
    // Sınıfta kişi var - timer'ı sıfırla
    global.set(classroomId + '_empty_timer', false);
    global.set(classroomId + '_empty_since', null);
    node.status({fill:'green', shape:'dot', text:personCount + ' kişi var'});
}

return null;

var classroomId = msg.classroomId || 'sinif-1';

// LED kapat
var ledMsg = {
    topic: 'akilli-sinif/' + classroomId + '/control/led',
    payload: { brightness: 0, reason: 'auto_empty' }
};

// Fan kapat
var fanMsg = {
    topic: 'akilli-sinif/' + classroomId + '/control/fan',
    payload: { speed: 0, reason: 'auto_empty' }
};

node.status({fill:'red', shape:'dot', text:'LED+Fan kapatıldı'});

return [ledMsg, fanMsg];

// Sıcaklık değiştiğinde kontrol et
var parts = msg.topic.split('/');
var classroomId = parts[1];
var temperature = msg.payload.value;

// Sınıfta kişi var mı kontrol et
var personCount = global.get(classroomId + '_person_count') || 0;

// Otomasyon durumunu kontrol et
var autoMode = global.get(classroomId + '_auto_mode');
if (autoMode === false || personCount === 0) {
    return null;  // Manuel mod veya sınıf boş
}

// Sıcaklık eşikleri
var FAN_ON_THRESHOLD = 26;   // 26°C üstünde fan aç
var FAN_OFF_THRESHOLD = 24;  // 24°C altında fan kapat

var currentFanState = global.get(classroomId + '_fan_auto_state') || false;

if (temperature > FAN_ON_THRESHOLD && !currentFanState) {
    // Sıcak - Fan aç
    global.set(classroomId + '_fan_auto_state', true);
    node.status({fill:'orange', shape:'dot', text:temperature + '°C - Fan açılıyor'});

    // Fan hızını sıcaklığa göre ayarla
    var fanSpeed = 50;
    if (temperature > 28) fanSpeed = 75;
    if (temperature > 30) fanSpeed = 100;

    msg.topic = 'akilli-sinif/' + classroomId + '/control/fan';
    msg.payload = { speed: fanSpeed, reason: 'auto_temp' };
    return msg;

} else if (temperature < FAN_OFF_THRESHOLD && currentFanState) {
    // Serin - Fan kapat
    global.set(classroomId + '_fan_auto_state', false);
    node.status({fill:'blue', shape:'dot', text:temperature + '°C - Fan kapatılıyor'});

    msg.topic = 'akilli-sinif/' + classroomId + '/control/fan';
    msg.payload = { speed: 0, reason: 'auto_temp' };
    return msg;
}

node.status({fill:'grey', shape:'ring', text:temperature + '°C'});
return null;

// Işık seviyesi değiştiğinde kontrol et
var parts = msg.topic.split('/');
var classroomId = parts[1];
var lightLevel = msg.payload.value;

// Sınıfta kişi var mı kontrol et
var personCount = global.get(classroomId + '_person_count') || 0;

// Otomasyon durumunu kontrol et
var autoMode = global.get(classroomId + '_auto_mode');
if (autoMode === false || personCount === 0) {
    return null;  // Manuel mod veya sınıf boş
}

// Işık eşikleri
var LED_ON_THRESHOLD = 300;   // 300 lux altında LED aç
var LED_OFF_THRESHOLD = 500;  // 500 lux üstünde LED kapat

var currentLedState = global.get(classroomId + '_led_auto_state') || false;

if (lightLevel < LED_ON_THRESHOLD && !currentLedState) {
    // Karanlık - LED aç
    global.set(classroomId + '_led_auto_state', true);
    node.status({fill:'yellow', shape:'dot', text:lightLevel + ' lux - LED açılıyor'});

    // LED parlaklığını ışık seviyesine göre ayarla
    var ledBrightness = 100;
    if (lightLevel > 200) ledBrightness = 75;
    if (lightLevel > 250) ledBrightness = 50;

    msg.topic = 'akilli-sinif/' + classroomId + '/control/led';
    msg.payload = { brightness: ledBrightness, reason: 'auto_light' };
    return msg;

} else if (lightLevel > LED_OFF_THRESHOLD && currentLedState) {
    // Aydınlık - LED kapat
    global.set(classroomId + '_led_auto_state', false);
    node.status({fill:'green', shape:'dot', text:lightLevel + ' lux - LED kapatılıyor'});

    msg.topic = 'akilli-sinif/' + classroomId + '/control/led';
    msg.payload = { brightness: 0, reason: 'auto_light' };
    return msg;
}

node.status({fill:'grey', shape:'ring', text:lightLevel + ' lux'});
return null;

// Her 30 saniyede bir sınıf boş mu kontrol et
var classroomId = 'sinif-1';
var personCount = global.get(classroomId + '_person_count') || 0;

// Kamera verisi simüle et
msg.topic = 'akilli-sinif/' + classroomId + '/sensors/camera';
msg.payload = { person_count: personCount };

return msg;

var autoMode = msg.payload;
global.set('sinif-1_auto_mode', autoMode);

if (autoMode) {
    node.status({fill:'green', shape:'dot', text:'Otomasyon AÇIK'});
} else {
    node.status({fill:'red', shape:'dot', text:'Otomasyon KAPALI'});
}

return msg;

// Topic: akilli-sinif/sinif-1/status/led veya fan
var parts = msg.topic.split('/');
var classroomId = parts[1];
var actuatorType = parts[3];  // led, fan

if (actuatorType === 'led') {
    msg.measurement = 'led_status';
    msg.payload = [
        { brightness: msg.payload.brightness || 0 },
        { classroom: classroomId, reason: msg.payload.reason || 'manual' }
    ];
} else if (actuatorType === 'fan') {
    msg.measurement = 'fan_status';
    msg.payload = [
        { speed: msg.payload.speed || 0 },
        { classroom: classroomId, reason: msg.payload.reason || 'manual' }
    ];
} else {
    return null;
}

return msg;

// Otomasyon olaylarını kaydet
var classroomId = msg.classroomId || 'sinif-1';
var reason = msg.payload.reason || 'unknown';
var actuator = msg.topic.includes('led') ? 'led' : 'fan';
var value = msg.payload.brightness || msg.payload.speed || 0;

msg.measurement = 'automation_event';
msg.payload = [
    { value: value, reason: reason },
    { classroom: classroomId, actuator: actuator }
];

return msg;

// GitHub API yanıtını işle
var release = msg.payload;

if (!release || !release.tag_name) {
    node.status({fill:'red', shape:'dot', text:'API hatası veya repo bulunamadı'});
    node.warn('GitHub API hatası: ' + JSON.stringify(release));
    return null;
}

var tagName  = release.tag_name;       // örn: v1.2.0
var version  = tagName.replace('v',''); // örn: 1.2.0
var assets   = release.assets || [];

// Binary URL'lerini bul
var plcUrl  = '';
var camUrl  = '';
var simUrl  = '';

assets.forEach(function(asset) {
    if (asset.name.includes('firmware-plc')) plcUrl = asset.browser_download_url;
    if (asset.name.includes('firmware-cam')) camUrl = asset.browser_download_url;
    if (asset.name.includes('firmware-sim')) simUrl = asset.browser_download_url;
});

// Global context'e kaydet (OTA trigger node'larının kullanması için)
global.set('ota_latest_version', version);
global.set('ota_latest_tag',     tagName);
global.set('ota_plc_url',        plcUrl);
global.set('ota_cam_url',        camUrl);
global.set('ota_sim_url',        simUrl);
global.set('ota_release_name',   release.name || tagName);
global.set('ota_release_date',   release.published_at);

node.status({fill:'green', shape:'dot', text:'Son: ' + tagName + ' (' + (new Date(release.published_at)).toLocaleDateString('tr-TR') + ')'});

msg.payload = {
    tag:     tagName,
    version: version,
    plc_url: plcUrl,
    cam_url: camUrl,
    sim_url: simUrl,
    date:    release.published_at
};

return msg;

