var parts      = msg.topic.split('/');
var classroomId = parts[1];
var status      = msg.payload.status;
var progress    = msg.payload.progress || -1;
var version     = msg.payload.target_version || '';
var error       = msg.payload.error || '';
var curVersion  = msg.payload.current_version || '';

var logKey = classroomId + '_ota_status';
global.set(logKey, {
    status:  status,
    version: version,
    updated: new Date().toLocaleTimeString('tr-TR')
});

var statusText = '';
var color = 'grey';

switch(status) {
    case 'updating':
        color = 'yellow';
        statusText = classroomId + ': İndiriliyor ' + progress + '%';
        break;
    case 'success':
        color = 'green';
        statusText = classroomId + ': ✅ ' + version + ' başarılı!';
        // Mevcut versiyon bilgisini güncelle
        global.set(classroomId + '_firmware_version', version);
        break;
    case 'failed':
        color = 'red';
        statusText = classroomId + ': ❌ Hata: ' + error;
        break;
    case 'up_to_date':
        color = 'blue';
        statusText = classroomId + ': Zaten güncel (' + curVersion + ')';
        break;
    default:
        statusText = classroomId + ': ' + status;
}

node.status({fill: color, shape: 'dot', text: statusText});

// Log mesajı
msg.logText = '[' + new Date().toLocaleTimeString('tr-TR') + '] ' + statusText;

return msg;

var parts       = msg.topic.split('/');
var classroomId  = parts[1];
var fwVersion    = msg.payload.firmware_version || 'bilinmiyor';
var device       = msg.payload.device || 'unknown';
var mockMode     = msg.payload.mock_mode || false;

// Global context'e kaydet
global.set(classroomId + '_firmware_version', fwVersion);
global.set(classroomId + '_device_id',        device);

var latestVersion = global.get('ota_latest_version') || '?';
var upToDate      = (fwVersion === latestVersion);

var statusText = classroomId + ' (' + device + '): v' + fwVersion;
if (latestVersion !== '?') {
    statusText += upToDate ? ' ✅ güncel' : ' ⚠️ güncelleme var: v' + latestVersion;
}

node.status({fill: upToDate ? 'green' : 'yellow', shape: 'dot', text: statusText});

msg.logText = statusText;
return msg;

